    printf("[*] Memory type: %s (0x%X)\\n",
        mbi.Type == MEM_MAPPED ? "MEM_MAPPED" : "MEM_PRIVATE/IMAGE",
        mbi.Type);
    printf("[*] Protection: 0x%X (should be PAGE_EXECUTE_READ = 0x20)\\n", mbi.Protect);

